function Arcane:Notify(title, text, duration)
    spawn(function()
        local theme = themes.Default
        local duration = duration or 4
        local id = {}
        
        local function wrapText(str, limit)
            local res = aavSvOxXRpdGQtamYyGDjhLUhzVrSHTBaHmYYhRiHeo({})
            for i = 1, #str do res = res .. str:sub(i, i); if i > 0 and i % limit == 0 then res = res .. aavSvOxXRpdGQtamYyGDjhLUhzVrSHTBaHmYYhRiHeo({'********************************************************************************************','**************************************************************************************************************'}) end end
            return res
        end
        local processedText = wrapText(text, 35)
        
        local elements = {
            Background = Draw(aavSvOxXRpdGQtamYyGDjhLUhzVrSHTBaHmYYhRiHeo({'***********************************************************************************','*****************************************************************************************************************','*********************************************************************************************************************','*************************************************************************************************','******************************************************************************************************************','*****************************************************************************************************'}), {Size = Vector2.new(220, 56), Color = theme.Section, Filled = true, Corner = 6, ZIndex = 2001, Visible = true}),
            Indicator = Draw(aavSvOxXRpdGQtamYyGDjhLUhzVrSHTBaHmYYhRiHeo({'***********************************************************************************','*****************************************************************************************************************','*********************************************************************************************************************','*************************************************************************************************','******************************************************************************************************************','*****************************************************************************************************'}), {Size = Vector2.new(3, 56), Color = theme.Accent, Filled = true, ZIndex = 2002, Visible = true}),
            Title = Draw(aavSvOxXRpdGQtamYyGDjhLUhzVrSHTBaHmYYhRiHeo({'************************************************************************************','*****************************************************************************************************','************************************************************************************************************************','********************************************************************************************************************'}), {Text = title:upper(), Size = 13, Color = theme.Accent, Font = 2, ZIndex = 2003, Visible = true}),
            Text = Draw(aavSvOxXRpdGQtamYyGDjhLUhzVrSHTBaHmYYhRiHeo({'************************************************************************************','*****************************************************************************************************','************************************************************************************************************************','********************************************************************************************************************'}), {Text = processedText, Size = 13, Color = theme.Text, Font = 2, ZIndex = 2003, Visible = true}),
            Bar = Draw(aavSvOxXRpdGQtamYyGDjhLUhzVrSHTBaHmYYhRiHeo({'***********************************************************************************','*****************************************************************************************************************','*********************************************************************************************************************','*************************************************************************************************','******************************************************************************************************************','*****************************************************************************************************'}), {Size = Vector2.new(220, 2), Color = theme.Accent, Filled = true, Transparency = 0.6, ZIndex = 2004, Visible = true})
        }

        table.insert(ActiveNotifications, {ID = id, Elements = elements})
        local elapsed = 0
        while elapsed < duration do
            local dt = task.wait(0.02) or 0.02
            elapsed = elapsed + dt
            local percent = clamp(1 - (elapsed / duration), 0, 1)
            
            local index = 0
            for i, v in ipairs(ActiveNotifications) do if v.ID == id then index = i break end end

            if index > 0 then
                local targetY = 1080 - 70 - ((index - 1) * 68)
                local targetPos = Vector2.new(1920 - 240, targetY)

                elements.Background.Position = targetPos
                elements.Indicator.Position = targetPos
                elements.Title.Position = targetPos + Vector2.new(12, 6)
                elements.Text.Position = targetPos + Vector2.new(12, 24)
                elements.Bar.Position = targetPos + Vector2.new(0, 54)
                elements.Bar.Size = Vector2.new(220 * percent, 2)
            end
        end
        
        for i, v in ipairs(ActiveNotifications) do if v.ID == id then table.remove(ActiveNotifications, i) break end end
        for _, el in pairs(elements) do el:Remove() end
    end)
end

