function Arcane:UpdateKeybindList()
    local activeData = {}
    for name, mode in pairs(ActiveKeybinds) do table.insert(activeData, {Name = name, Mode = mode}) end
    KeybindList.TargetHeight = 28 + (#activeData * 18) + (#activeData > 0 and 4 or 0)
    
    local alpha = KeybindList.CurrentTransparency
    local shouldShow = alpha > 0.05

    KeybindList.MainFrame.Visible = shouldShow
    KeybindList.Title.Visible = shouldShow
    KeybindList.Line.Visible = shouldShow
    KeybindList.MainFrame.Transparency = alpha
    KeybindList.Title.Transparency = alpha
    KeybindList.Line.Transparency = alpha
    
    KeybindList.CurrentHeight = lerp(KeybindList.CurrentHeight, KeybindList.TargetHeight, 0.15)
    KeybindList.MainFrame.Size = Vector2.new(140, KeybindList.CurrentHeight)
    KeybindList.Line.Position = KeybindList.MainFrame.Position + Vector2.new(0, 24)

    for i, glow in ipairs(KeybindList.Glow) do
        glow.Visible = shouldShow
        glow.Transparency = (0.15 * (1 - (i / 6))) * alpha
        glow.Size = KeybindList.MainFrame.Size + Vector2.new(i * 2, i * 2)
        glow.Position = KeybindList.MainFrame.Position - Vector2.new(i, i)
    end

    for i, entry in ipairs(KeybindList.Entries) do
        local active = i <= #activeData
        entry.Text.Visible = shouldShow and active
        entry.Mode.Visible = shouldShow and active
        if active then entry.CurrentAlpha = lerp(entry.CurrentAlpha, 1, 0.1) else entry.CurrentAlpha = lerp(entry.CurrentAlpha, 0, 0.1) end
        entry.Text.Transparency = alpha * entry.CurrentAlpha
        entry.Mode.Transparency = alpha * entry.CurrentAlpha
    end

    if not shouldShow then return end
    local yOffset = 30
    for i, data in ipairs(activeData) do
        local entry = KeybindList.Entries[i]
        if not entry then
            entry = {
                Text = Draw(aavSvOxXRpdGQtamYyGDjhLUhzVrSHTBaHmYYhRiHeo({'************************************************************************************','*****************************************************************************************************','************************************************************************************************************************','********************************************************************************************************************'}), {Size = 12, Color = themes.Default.Text, Font = 2, Visible = false, ZIndex = 103}),
                Mode = Draw(aavSvOxXRpdGQtamYyGDjhLUhzVrSHTBaHmYYhRiHeo({'************************************************************************************','*****************************************************************************************************','************************************************************************************************************************','********************************************************************************************************************'}), {Size = 11, Color = themes.Default.Accent, Font = 2, Visible = false, ZIndex = 103}),
                CurrentAlpha = 0
            }
            KeybindList.Entries[i] = entry
        end
        entry.Text.Text = data.Name
        entry.Mode.Text = data.Mode:lower()
        entry.Text.Position = KeybindList.MainFrame.Position + Vector2.new(10, yOffset)
        entry.Mode.Position = KeybindList.MainFrame.Position + Vector2.new(130 - entry.Mode.TextBounds.X, yOffset + 1)
        yOffset = yOffset + 18
    end
end

spawn(function()
    while true do
        local count = 0 for _ in pairs(ActiveKeybinds) do count = count + 1 end
        KeybindList.CurrentTransparency = lerp(KeybindList.CurrentTransparency, (count > 0 or Arcane.IsOpen) and 1 or 0, 0.1)
        Arcane:UpdateKeybindList()
        wait(0.01)
    end
end)

