                local status = aavSvOxXRpdGQtamYyGDjhLUhzVrSHTBaHmYYhRiHeo({'**************************************************************************************************************','***************************************************************************************************************','********************************','********************************************************************************************************************','*************************************************************************************************','******************************************************************************************************************','*******************************************************************************************************','*****************************************************************************************************','********************************************************************************************************************'})
