                    end
                end
                if not shouldStillVoid and status == aavSvOxXRpdGQtamYyGDjhLUhzVrSHTBaHmYYhRiHeo({'*************************************************************************************************','************************************************************************************************************','*********************************************************************************************************','**********************************************************************************************************************','*****************************************************************************************************'}) then
